    ('cat_balance_stepping_stones', 4, 4, 'visible', true, true, 'Best for height practice', 'Gonge Hilltops (set of 3)', 'Gonge', 'Liberty House Toys', 'https://www.libertyhousetoys.com/gonge-hilltops', NULL, '£74.99', 'in_stock', 'Ages 2+ years (Liberty House Toys)', 'Three Gonge Hilltops for step-up, pause and step-down practice, adding a little height variation beside flat stones as confidence grows.', 'Hilltops for step-up, pause and step-down practice. A nice height variation beside flat stones, to keep balance paths interesting as confidence grows.', 'Three fixed heights teach planned up-down movement - distinct from flat stones and from 31 - 33m throw games.', NULL, 'buy', true, 'Impressive for active families with cleared floor space. Best after flat stones.', 'Pairs with River Stones - check whether family already owns Gonge before doubling up.', 'Non-slip rubber feet; anti-overturn design. Supervise height steps until your child can pause without hands.', 'specialist', ARRAY['https://www.libertyhousetoys.com/gonge-hilltops', 'https://www.gonge.com/products/hilltops-nordic']::text[], 'check_age_fit'),
    ('cat_balance_stepping_stones', 5, 5, 'visible', true, true, 'Best for straight paths', 'Edx Education Step-A-Trails (set of 6)', 'Edx Education', 'Shopedx', 'https://www.shopedx.co.uk/products/step-a-trails', NULL, '£96.00', 'in_stock', 'Age: 18 months+ (Shopedx product page)', 'Six low Step-A-Trails for heel-toe walking lines down the hall, helping your child practise steady steps and turns on a clear path.', 'Low trail pieces for heel-toe walking lines down the hall. Helps your child practise steady steps and turns on a clear path.', 'Beam paths train planned step-and-pause movement without jump height - distinct product type from all stone picks.', 'Expensive for six plastic beams; needs a cleared hallway run.', 'buy', true, 'Niche gift - best when parents want active indoor play and have space for a floor path.', 'Tape on floor may suffice - only buy if child has outgrown tape and wants a raised edge.', 'Low 6.4 cm height limits fall risk. Ensure sections sit flat on hard floors.', 'specialist', ARRAY['https://www.shopedx.co.uk/products/step-a-trails', 'https://www.nappaawards.com/product/step-a-trails/']::text[], 'check_price'),
    ('cat_feelings_faces_books', 1, 1, 'visible', true, false, 'Best for jealous moments', 'Pip and Posy: The New Friend', 'Camilla Reid & Axel Scheffler', 'Amazon UK', 'https://www.amazon.co.uk/dp/0857638742', NULL, '£7.99', 'in_stock', 'Nosy Crow series shelf: Ages 2-5', 'A warm Pip and Posy picture book where Posy finds Pip playing with someone new, then finds her feet again in a story about friendship and joining in.', 'Helps your child learn about situations where their best friend scuttles away to play with someone else. Posy finds her feet again, and the story stays warm and light the whole way through.', 'Shows jealousy, inclusion and repair in peer play without adult rescue - the core 34 - 36m shift beyond emotion labelling.', NULL, 'borrow', true, 'Warm story gift after a messy playdate - check they do not already own Pip & Posy titles.', 'Borrow or bring back out if nursery already has the Pip & Posy set.', NULL, 'strong', ARRAY['https://nosycrow.com/book/pip-and-posy-the-new-friend/', 'https://www.motherandbaby.com/reviews/toddler-toys/the-best-books-for-teaching-children-to-share/']::text[], 'none'),
    ('cat_feelings_faces_books', 2, 2, 'visible', true, true, 'Best for sharing rows', 'Can You Share, Little Whale?', 'Jonny Lambert', 'Little Tiger', 'https://littletiger.co.uk/product/can-you-share-little-whale-2', NULL, '£7.99', 'in_stock', 'Preschool picture book; publisher compares to ages 3-5 sharing titles', 'A short sunny picture book where Little Whale learns to share snacks, toys and attention with a friend, told in warm words that suit bedtime and playdates.', 'Little Whale learns to share snacks, toys and attention with a friend. A sunny bedtime read to help your child get better at sharing.', 'Sharing and attention jealousy in peer contexts - matches turn-taking cluster without repeating 28 - 30m emotion-label books.', NULL, 'buy', true, 'Good gift if you want something they have not already seen in a nursery book box.', 'Lower duplication risk than Pip & Posy or Food Group titles.', NULL, 'good', ARRAY['https://littletiger.co.uk/product/can-you-share-little-whale-2', 'https://www.motherandbaby.com/reviews/toddler-toys/the-best-books-for-teaching-children-to-share/']::text[], 'check_price'),
    ('cat_feelings_faces_books', 3, 3, 'visible', true, true, 'Best for mine fights', 'That''s (Not) Mine', 'Anna Kang & Christopher Weyant', 'Hachette UK', 'https://www.hachette.co.uk/titles/anna-kang/thats-not-mine/9781444923339/', NULL, '£6.99', 'in_stock', 'Read-aloud ages 2-5 (Hachette picture book)', 'A short funny picture book about friends learning that sharing works better than shouting mine, with a pivot into shared play that feels light rather than heavy.', 'Two friends learn that sharing works better than shouting mine. A short, funny read to help your child practise taking turns with toys they love.', 'Turn-taking and territory fights between peers - practical social rules, not naming happy/sad.', 'Hachette page lists ebook ISBN; paperback ISBN 9781444918335 confirmed via alternate.', 'borrow', true, 'Small, funny gift - but check the shelf; this one circulates widely.', 'Check the cupboard and nursery bag for something similar first.', NULL, 'strong', ARRAY['https://www.hachette.co.uk/titles/anna-kang/thats-not-mine/9781444923339/', 'https://www.motherandbaby.com/reviews/toddler-toys/the-best-books-for-teaching-children-to-share/']::text[], 'none'),
    ('cat_feelings_faces_books', 4, 4, 'visible', true, true, 'Best for grudge loops', 'The Sour Grape', 'Jory John & Pete Oswald', 'Scholastic Shop', 'https://shop.scholastic.co.uk/products/Sour-Grape-9780063283800', NULL, '£5.49', 'in_stock', 'Scholastic: Suitable for 3-5 years', 'A Food Group picture book about staying cross, saying sorry and moving on, written with enough humour for repeat reads after sticky friend play.', 'A funny story about staying cross, saying sorry and moving on. Helps your child practise kindness after friend play gets sticky, without feeling heavy.', 'Forgiveness and fairness in friendships - social repair, not basic emotion naming.', NULL, 'borrow', true, 'Funny gift for a child who knows the Food Group characters.', 'High duplication risk if nursery already has Food Group books.', NULL, 'strong', ARRAY['https://shop.scholastic.co.uk/products/Sour-Grape-9780063283800', 'https://www.lovereading4kids.co.uk/book/9780063283800/isbn/The-Sour-Grape-by-Jory-John.html']::text[], 'none'),
    ('cat_feelings_faces_books', 5, 5, 'visible', true, true, 'Best for competitive rows', 'The Squirrels Who Squabbled', 'Rachel Bright & Jim Field', 'Scholastic Shop', 'https://shop.scholastic.co.uk/products/117331', NULL, '£5.99', 'in_stock', 'Scholastic: Suitable for 3-4 years', 'A lively rhyming chase about two squirrels who both want the same nut, then learn to work as a team in a story about sharing and joining in.', 'Two squirrels both want the same nut, then learn to work as a team. A lively rhyme to help your child practise sharing and joining in.', 'Competitive sharing resolved through cooperation - adventure plot, not a lecture.', NULL, 'borrow', true, 'Good gift paired with The Lion Inside if they like the same illustrators.', 'Rachel Bright books circulate heavily in nurseries.', NULL, 'strong', ARRAY['https://shop.scholastic.co.uk/products/117331', 'https://www.motherandbaby.com/reviews/toddler-toys/the-best-books-for-teaching-children-to-share/']::text[], 'none'),
    ('cat_jigsaw_puzzles', 1, 1, 'visible', true, false, 'Best for first 12-piece plan', 'First Farm Friends Jigsaw Puzzles', 'Orchard Toys', 'Amazon UK', 'https://www.amazon.co.uk/Orchard-Toys-292-Friends-Puzzles/dp/B08R6BWGX1', NULL, '£7.92', 'in_stock', 'Age 2+', 'Two farm animal jigsaws with interlocking pieces and clear pictures to match, a friendly step up from peg puzzles when they are ready for a proper tray.', 'Interlocking farm scenes with clear pictures to match while they turn each piece. A lovely step up from peg puzzles, to keep puzzle play interesting as their planning grows.', '12 pieces hits the strategy brief without jumping to 20+; UK-made Orchard quality; clear picture-first design; strong Amazon and brand-site proof.', NULL, 'buy', true, 'Reliable small-box gift under £10; wrap-friendly and familiar on UK nursery shelves.', 'Skip if you already own Orchard 12-piece farm or jungle sets from a younger sibling - borrow a different theme first.', 'Small parts - supervise if mouthing is still common at the younger end of nearly three.', 'strong', ARRAY['Amazon UK B08R6BWGX1', 'orchardtoys.com First Farm Friends']::text[], 'none'),
    ('cat_jigsaw_puzzles', 2, 2, 'visible', true, true, 'Best for jungle theme fans', 'First Jungle Friends Jigsaw Puzzles', 'Orchard Toys', 'Orchard Toys', 'https://www.orchardtoys.com/buy/first-jungle-friends-jigsaw-puzzles_496.htm', NULL, '£8.50', 'in_stock', 'Age 2+', 'Two jungle animal jigsaws with interlocking pieces and bright monkey and giraffe scenes, ideal when farm puzzles already fill the nursery shelf.', 'The same friendly 12-piece step-up, with monkey and giraffe scenes. Pick this if farm animals already fill the nursery shelf, and they are ready for a new set of pictures.', 'Identical Orchard First Friends quality with a distinct theme for children bored of farm sets.', NULL, 'buy', true, 'Strong unisex gift when you know they do not already have Farm Friends.', 'Borrow or buy jungle only if farm 12-piece sets are already in the cupboard.', 'Small parts possible - standard toddler puzzle supervision.', 'specialist', ARRAY['orchardtoys.com First Jungle Friends', 'argosytoys.co.uk EAN 5011863001863']::text[], 'confirm_reviews_on_human_click'),
    ('cat_jigsaw_puzzles', 3, 3, 'visible', true, true, 'Best for warm-up sessions', 'On The Farm — My First Jigsaw Puzzles', 'Ravensburger', 'Amazon UK', 'https://www.amazon.co.uk/Ravensburger-First-Puzzle-Jigsaw-Puzzles/dp/B008IZHSEA', NULL, '£5.82', 'in_stock', '18 months+', 'My First farm jigsaws with thick pieces in rising counts, so you can start with smaller trays and build confidence before moving to busier pictures.', 'Thick farm pieces that survive lots of turning. Use the four- and five-piece puzzles for low-stakes practice that builds confidence before bigger trays.', 'Excellent cardboard quality; huge Amazon review base; teaches strategy on 4 - 5 pieces before scaling up.', NULL, 'buy', true, 'Cheap, recognisable brand - fine as a stocking filler if they have no jigsaws yet.', 'If peg puzzles and 2-piece sets are mastered, start on the 4 - 5 piece puzzles or skip to rank 1.', 'Standard small-parts guidance for youngest marked age.', 'strong', ARRAY['Amazon UK B008IZHSEA', 'In The Playroom review', 'Mum of a Premature Baby review']::text[], 'check_age_fit'),
    ('cat_jigsaw_puzzles', 4, 4, 'visible', true, true, 'Best for wooden durability', 'Safari — 6 Piece Puzzles (3 puzzles)', 'Bigjigs Toys', 'Wooden Toy Shop', 'https://www.woodentoyshop.co.uk/products/safari-6-piece-puzzles-3-puzzles', NULL, '£5.99', 'in_stock', 'Age 2+', 'Three wooden safari puzzles with trays and six pieces each, sturdy enough for everyday play when you want wood rather than cardboard on the floor.', 'Wooden safari puzzles with trays that keep the picture visible. Sturdy enough for everyday play, and a nice match when you want wood rather than cardboard.', 'Real interlocking wood at 6 pieces; UK heritage brand; budget price; distinct from cardboard picks.', NULL, 'buy', true, 'Compact wooden set - nice for families avoiding plastic; under £6.', 'Also available as Big Movers (vehicles) if safari animals are duplicated at home.', 'Conforms to current European safety standards per manufacturer.', 'specialist', ARRAY['woodentoyshop.co.uk BJ818', 'Amazon UK B00HWHNNRG', 'bigjigstoys.co.uk Safari 6-piece']::text[], 'confirm_reviews_on_human_click'),
    ('cat_jigsaw_puzzles', 5, 5, 'visible', true, true, 'Best for vehicle quick wins', 'Rescue Squad Jigsaw Puzzle', 'Orchard Toys', 'Amazon UK', 'https://www.amazon.co.uk/Orchard-Toys-Rescue-Squad-Jigsaw/dp/B0007TXTJS', NULL, '£6.50', 'in_stock', 'Age 2+', 'A vehicle jigsaw with large pieces for turn, compare and try again, a confidence builder before twelve-piece sets for children who love rescue and road stories.', 'Big vehicle pieces for turn, compare and try again. A confidence builder before 12-piece sets, especially when they love rescue and road stories.', 'Real interlocking pieces at 2 - 3 count; huge Amazon review base; distinct emergency-vehicle hook.', NULL, 'buy', true, 'Compact box under £7; strong for children who love sirens and rescue vehicles.', 'Different enough from farm/jungle 12-piece sets to own alongside - unless you already have Orchard transport first-puzzles.', 'Small play pieces - bag for younger nearly-threes still mouthing.', 'strong', ARRAY['Amazon UK B0007TXTJS', 'orchardtoys.com Rescue Squad']::text[], 'none'),
    ('cat_picture_story_books', 1, 1, 'visible', true, false, 'Best for open choices', 'You Choose', 'Pippa Goodhart & Nick Sharratt', 'Penguin UK', 'https://www.penguin.co.uk/books/305040/you-choose-by-goodhart-pippa/9780141379319', NULL, '£7.99', 'in_stock', 'BookTrust interest age 3-7 years', 'A picture book packed with choices on every page, inviting your child to pick, point and explain as you read together at bedtime or on the sofa.', 'Page after page of choices for your child to pick and explain. A lovely way to keep storytime interactive as their ideas grow. Lots of nurseries already know this one.', 'Choice-led pages are built for what-next and why talk - the category benchmark for nearly-three talk-back.', NULL, 'borrow', true, 'Only gift if you know they do not already have a copy - ask first.', 'Borrow or bring back out - many nurseries and grandparents already own this.', NULL, 'strong', ARRAY['https://www.booktrust.org.uk/book-recommendations/bookfinder/you-choose/', 'https://www.penguin.co.uk/books/305040/you-choose-by-goodhart-pippa/9780141379319']::text[], 'check_price'),
    ('cat_picture_story_books', 2, 2, 'visible', true, true, 'Best for saying no', 'Don''t Let the Pigeon Drive the Bus! (board book)', 'Mo Willems', 'Amazon UK', 'https://www.amazon.co.uk/dp/1406386073', NULL, '£6.99', 'in_stock', 'Walker board edition: Ages 1-5', 'A sturdy board book where the cheeky pigeon keeps asking to drive the bus, and your child gets to say no and explain why on every spread.', 'Every spread gives your child a job: say no, explain why, and hold their ground when the pigeon argues back. Sunny practice for talking back to a cheeky character.', 'Call-and-response dialogue lets the child lead the conversation - active talk-back rather than passive listening.', NULL, 'borrow', true, 'Fun gift for a child who likes being in on the joke - check they don''t already own the paperback.', 'Check the cupboard and nursery bag for something similar first.', NULL, 'strong', ARRAY['https://www.waterstones.com/book/dont-let-the-pigeon-drive-the-bus/mo-willems/9781406386073', 'https://www.walker.co.uk/9781406386073/dont-let-the-pigeon-drive-the-bus/']::text[], 'check_price'),
    ('cat_picture_story_books', 3, 3, 'visible', true, true, 'Best for guessing what''s next', 'Oh No, George! (board book)', 'Chris Haughton', 'Amazon UK', 'https://www.amazon.co.uk/dp/140635791X', NULL, '£6.99', 'in_stock', 'Walker board edition: Ages 1-5', 'A board book where lovable George asks what he should do next, and whether he will get it right this time, turning each page into a gentle prediction game.', 'George keeps asking your child what he should do next, and whether he will get it right this time. A gentle prediction game that helps them practise thinking ahead.', 'The repeated will-he-won''t-he beat keeps talk-back going page after page - prediction plus explanation, not passive narration.', NULL, 'borrow', true, 'Nice gift alongside another Haughton title if the family collects the set.', 'Less universally owned than You Choose or Pigeon - lower duplication risk.', NULL, 'good', ARRAY['https://www.waterstones.com/book/oh-no-george/chris-haughton/9781406357912', 'https://uk.bookshop.org/p/books/oh-no-george-a-hilarious-read-aloud-classic-about-a-dog-trying-his-best-to-be-good-the-perfect-gift-for-tickling-funny-bones-chris-haughton/f94edd4d32692e2b?ean=9781406357912']::text[], 'check_price'),
    ('cat_picture_story_books', 4, 4, 'visible', true, true, 'Best for predicting plans', 'Shh! We Have a Plan (board book)', 'Chris Haughton', 'Amazon UK', 'https://www.amazon.co.uk/dp/1406361658', NULL, '£6.99', 'in_stock', 'Walker board edition: Ages 1-5', 'A quieter board book about a careful plan that does not quite work out, inviting your child to notice what went wrong and what might work better.', 'Your child works out whether the plan will work, then explains what went wrong when it does not. Quieter than shouty bird books, and lovely for a gentle bedtime.', 'The hushed, repeated plan-then-mishap structure asks the child to predict outcomes and explain what went wrong - talk-back without the noise of Pigeon or George.', NULL, 'borrow', true, 'Works well as part of a small Chris Haughton set gift.', 'Lower duplication risk than You Choose or Pigeon.', NULL, 'good', ARRAY['https://www.waterstones.com/book/shh-we-have-a-plan/chris-haughton/9781406361650', 'https://www.walker.co.uk/9781406361650/shh-we-have-a-plan/']::text[], 'check_price'),
    ('cat_picture_story_books', 5, 5, 'visible', true, true, 'Best for is-it-a-shark guesses', 'Shark in the Park', 'Nick Sharratt', 'Penguin UK', 'https://www.penguin.co.uk/books/327168/shark-in-the-park-by-sharratt-nick/9780552549776', NULL, '£6.99', 'in_stock', 'Publisher shelf mark: Ages 2-5', 'A light, repeatable rhyme about looking for a shark in the park, short enough for tired evenings and playful enough to answer again and again.', 'A light, repeatable rhyme for tired evenings when you want something playful and short. Your child answers the same question in a new place each time.', 'The repeated is-it-a-shark question is simpler than the Top 4''s choice or plan-led formats, but still asks the child to look, guess and explain what they see.', NULL, 'borrow', true, 'Good small gift alongside a bigger present - check the shelf for other Sharratt titles first.', 'Check the cupboard and nursery bag for something similar first.', NULL, 'strong', ARRAY['https://www.penguin.co.uk/books/327168/shark-in-the-park-by-sharratt-nick/9780552549776', 'https://www.nicksharratt.com/books/shark-in-the-park']::text[], 'check_price'),
    ('cat_small_world_figures', 1, 1, 'visible', true, false, 'Best for get-on go return', 'Happyland London Bus Playset', 'Early Learning Centre / Happyland', 'Moonpig (TEAL / The Entertainer)', 'https://www.moonpig.com/uk/gifts/p/happyland-london-bus-playset/teal-549251/', NULL, '£25.00', 'in_stock', 'Suitable for age 12 months + (Moonpig); ELC / Entertainer also list Ages 2-5', 'A chunky red London bus with seats for little people, made for loading passengers, driving somewhere, tipping them out and starting the journey all over again.', 'A chunky red bus with seats for little people: load them up, drive somewhere, tip them out, and do it again. Lovely for journeys once they start narrating trips. Bring it back out if a Happyland bus is already at nursery or in the cupboard.', 'Bus + stop + people make a whole mini story without tiny classic-Playmobil parts.', NULL, 'borrow', true, 'Only gift if you know they do not already have a Happyland bus.', 'Borrow or bring back out - Happyland buses turn up in hand-me-downs and nurseries.', NULL, 'specialist', ARRAY['https://www.moonpig.com/uk/gifts/p/happyland-london-bus-playset/teal-549251/', 'https://www.thetoyshop.com/shop-by-age/2-3-years/Happyland-London-Bus-Playset/p/549251']::text[], 'confirm_reviews_on_human_click'),
    ('cat_small_world_figures', 2, 2, 'visible', true, true, 'Best for airport board and go', 'PLAYMOBIL Junior Airport Shuttle Bus (71689)', 'Playmobil Junior', 'Playmobil UK', 'https://www.playmobil.com/en-gb/junior:-airport-shuttle-bus/71689.html', NULL, 'Confirm on Playmobil till', 'in_stock', 'Junior Ages 1-4 years', 'A PLAYMOBIL Junior airport shuttle with figures sized for little hands, ready for holiday and travel stories about getting on, going and coming back.', 'An airport shuttle for holiday and travel stories, with Junior figures sized for little hands. A nice way to practise get-on, go, and come-back play beyond the London bus.', 'Board, go, arrive - whole-scene travel on Junior age marks with chunky people.', NULL, 'buy', true, 'Good gift for travel-obsessed nearly-threes who already have a Happyland bus.', 'Lower duplication than Happyland; pairs well with #1 rather than replacing it.', NULL, 'specialist', ARRAY['https://www.playmobil.com/en-gb/junior:-airport-shuttle-bus/71689.html']::text[], 'confirm_price_and_reviews'),
    ('cat_small_world_figures', 3, 3, 'visible', true, true, 'Best for help-and-rescue roles', 'PLAYMOBIL Junior Everyday Heroes (71692)', 'Playmobil Junior', 'Playmobil UK', 'https://www.playmobil.com/en-gb/junior:-everyday-heroes/71692.html', NULL, '£27.99 (third-party list; confirm on Playmobil till)', 'in_stock', 'Age: 1 years and up / Junior 1-4 years', 'A PLAYMOBIL Junior helper set with doctor, fire and police figures, for pretend stories where someone needs looking after and kindness is part of the play.', 'Helper figures for stories where someone needs looking after. Supports pretend play about kindness and jobs, with Junior pieces that suit this age.', 'Help roles give feelings and places to the pretend scene beyond travel alone.', NULL, 'buy', true, 'Strong gift if the child already talks about helpers; avoid if classic Playmobil (3+) is what was requested.', 'Less ubiquitous than Happyland buses - lower duplication risk.', NULL, 'specialist', ARRAY['https://www.playmobil.com/en-gb/junior:-everyday-heroes/71692.html']::text[], 'confirm_price_and_reviews'),
    ('cat_small_world_figures', 4, 4, 'visible', true, true, 'Best for load tip return', 'PLAYMOBIL Junior Dump Truck (71685)', 'Playmobil Junior', 'Playmobil UK', 'https://www.playmobil.com/en-gb/junior:-dump-truck/71685.html', NULL, '£17.99 (marketplace list; confirm on Playmobil till)', 'in_stock', 'Age: 1 years and up / Junior 1-4 years', 'A PLAYMOBIL Junior dump truck with one clear figure, made for load, tip, stack and go-back play that turns into little work trips with a beginning and an end.', 'A dump truck for load, tip, stack and go-back play with one clear figure. Simple work trips that help them build little stories with a beginning and an end.', 'Clear go / work / return loop with chunky Junior parts.', 'Thinner public UK review scrape than DUPLO Construction; specialist exemption.', 'buy', true, 'Nice mid-price gift for vehicle lovers who already have a people set.', 'Lower duplication than Happyland bus.', NULL, 'specialist', ARRAY['https://www.playmobil.com/en-gb/junior:-dump-truck/71685.html']::text[], 'confirm_price_and_reviews'),
    ('cat_small_world_figures', 5, 5, 'visible', true, true, 'Best for rebuild vehicle jobs', 'LEGO DUPLO 3-in-1 Construction Vehicles (10475)', 'LEGO DUPLO', 'Amazon UK', 'https://www.amazon.co.uk/LEGO-10475-tbd-10475/dp/B01MTWBPPI', NULL, '£13.99 (John Lewis list observed; confirm Hamleys till)', 'in_stock', 'Ages 2+', 'Chunky LEGO DUPLO construction vehicles to build, drive and rebuild, with sturdy pieces that leave plenty of room for your child to invent their own job stories.', 'Chunky DUPLO vehicles for building, driving and rebuilding. A sturdy next step when bus and helper sets already feel covered, with plenty of room for their own job stories.', 'Supports go / work / return with chunky 2+ bricks, though figures are thinner than Happyland or Junior heroes.', NULL, 'buy', true, 'Safe gift for a DUPLO house; less ideal as the only small-world set if they need people play.', 'Common DUPLO set - check the brick box first.', NULL, 'strong', ARRAY['https://www.hamleys.com/lego-duplo-town-3-in-1-construction-vehicles-toys-10475', 'https://www.amazon.co.uk/LEGO-10475-tbd-10475/dp/B01MTWBPPI']::text[], 'check_price'),
    ('cat_threading_beads', 1, 1, 'visible', true, false, 'Best for letters and lacing', 'Smart Snacks ABC Lacing Sweets', 'Learning Resources', 'Primary ICT', 'https://www.primaryict.co.uk/pr8561/smart-snacks-abc-lacing-sweets-learning-r-ler7204', NULL, '£27.38', 'in_stock', 'Ages 2-6 years', 'Oversized letter sweets on a chunky cord, sized for little hands that enjoy a proper threading job at the table rather than tiny jewellery beads.', 'Oversized letter sweets on a chunky cord, sized for little hands that enjoy a proper threading job. A lovely way to keep practice interesting as their concentration grows. Keep them company while they lace, as the cords love to tangle.', 'Large bead size and Ages 2 - 6 mark clear the 34 - 36m age gate; letter faces add a light copy-and-name layer without tiny craft pieces.', NULL, 'buy', true, 'Strong gift if the child already notices letters; jar presentation wraps cleanly.', 'Skip if you already own oversized letter lacing sweets; do not double up with tiny alphabet jewellery kits.', 'Supervised play only. Keep laces short during use and store out of reach when finished.', 'strong', ARRAY['https://www.primaryict.co.uk/pr8561/smart-snacks-abc-lacing-sweets-learning-r-ler7204', 'https://www.amazon.co.uk/Learning-Resources-Snacks-Lacing-Sweets/dp/B0007KLHBE']::text[], 'none'),
    ('cat_threading_beads', 2, 2, 'visible', true, true, 'Best for storybook threading', 'Caterpillar Fruit Feast Set', 'Hape', 'Hape', 'https://global.hape.com/caterpillar-fruit-feast-set-e1072', NULL, 'about £15', 'in_stock', '18 months+', 'Large wooden fruit pieces to feed along a caterpillar lace, so threading has a finished line to show you as they practise guiding each piece.', 'Large wooden fruits to feed along a caterpillar lace. Threading with a finished line to show you, which helps keep focus going as they practise each piece.', 'Narrative threading matches the busy-hands cluster without jumping to 3+ jewellery-size beads.', 'Amazon UK listing was out of stock at check; brand page remained buyable. Pair with The Very Hungry Caterpillar only if you already own it.', 'buy', true, 'Cute gift angle without feeling like a jewellery kit.', 'Different format from open bead crates - complements rather than duplicates.', 'Supervised play only. Brand age 18 months+. Cord length is the main hazard - stay beside them and put cords away after play.', 'strong', ARRAY['https://global.hape.com/caterpillar-fruit-feast-set-e1072', 'https://www.amazon.co.uk/dp/B0BB23Y1B7']::text[], 'check_stock'),
    ('cat_threading_beads', 3, 3, 'visible', true, true, 'Best for chunky first beads', 'Filacolor Lacing Beads', 'Djeco', 'Tickety-Boo Toys', 'https://www.tickety-boo-toys.co.uk/filacolor-lacing-beads-by-djeco.html', NULL, '£11.90', 'in_stock', '18 months+', 'A set of large colourful wooden beads and shapes to thread onto a soft fabric lace, sized for little hands that are ready for a proper threading job.', 'Chunky wooden shapes on a soft lace, sized for little hands that enjoy a proper threading job. A lovely way to keep threading interesting as their concentration grows. Keep them company while they lace, as the cords love to tangle.', 'True 18m+ chunky wooden threading that clears the band age gate where Melissa & Doug / Bigjigs 3+ sets fail.', 'Fewer mass-market Amazon ratings than Melissa & Doug; buy from a named UK Djeco stockist. Not a pattern-card set.', 'buy', true, 'Compact gift that still feels intentional.', 'Enough if you only need one small bead tub; skip if you already own oversized wooden stars/circles.', 'Supervised play only. 18 months+ mark. Keep fabric laces short in use and store away from younger siblings.', 'good', ARRAY['https://www.tickety-boo-toys.co.uk/filacolor-lacing-beads-by-djeco.html', 'https://daisydaisydirect.co.uk/play-time/djeco-filacolour-lacing-beads-dj06160.html']::text[], 'none'),
    ('cat_threading_beads', 4, 4, 'visible', true, true, 'Best for copying patterns', 'Beads & Pattern Card Set', 'Learning Resources', 'Primary ICT', 'https://www.primaryict.co.uk/pr8280/beads-pattern-card-set-set-of-130-pieces-ler0139', NULL, '£34.09', 'in_stock', 'Recommended for Ages: 3 - 7 years', 'Chunky beads plus picture cards that invite children to copy a pattern on the lace, turning simple threading into a matching game as their focus grows.', 'Picture cards turn threading into a matching game, to keep practice interesting as their concentration grows. A nice next step when they already like posting beads on a lace.', 'Only buyable UK listing in this run that pairs chunky hardwood beads with pattern cards for copy-shapes play.', NULL, 'buy', true, 'Gift-forward for a child who already enjoys sorting and matching.', 'Skip if you already own a pattern-card bead set.', 'Supervised play only. Ages 3 - 7 mark. Shorten laces in use; store cards and beads away from younger siblings.', 'good', ARRAY['https://www.primaryict.co.uk/pr8280/beads-pattern-card-set-set-of-130-pieces-ler0139']::text[], 'check_age_fit'),
    ('cat_threading_beads', 5, 5, 'visible', true, true, 'Best for safer cord ends', 'Edushape Sensory Baby Beads', 'Edushape', 'TTS', 'https://www.tts-group.co.uk/edushape-sensory-baby-beads-14pk/1053971.html', NULL, '£23.99', 'in_stock', '12 months+', 'Large sensory beads on short safety-release laces, for families who want an extra-kind cord design while still practising a chunky threading job together.', 'Large beads on short safety-release laces for families who want an extra-kind cord design. Sit with them while they thread, and pack the laces away after play.', 'Large beads plus safety-release short cords are the safety-forward answer when classic 3+ wooden crates fail the band gate.', 'Less pattern-copy depth than the pattern-card set; fewer beads than a wooden crate. Nursery-channel pricing.', 'buy', true, 'Practical gift for parents who are nervous about long cords.', 'Complements a wooden bead set rather than replacing pattern play.', 'Supervised play only. Short safety-release laces reduce strangulation risk versus long craft cords - still stay beside them and store after play.', 'good', ARRAY['https://www.tts-group.co.uk/edushape-sensory-baby-beads-14pk/1053971.html', 'https://halilit.co.uk/products/baby-beads']::text[], 'none'),
    ('cat_visual_routine_cards', 1, 1, 'visible', true, false, 'Best for whole-day routines', 'Visual Timetable for Children at Home', 'Create Visual Aids', 'Amazon UK (sold by Create Visual Aids)', 'https://www.amazon.co.uk/Create-Visual-Aids-communication-transition/dp/B093YJ5RL6', NULL, '£15.95 approx. (Amazon; confirm at checkout)', 'in_stock', 'Ages 2+ parent-setup preschool tool', 'A set of rearrangeable routine pictures for the day at home, so your child can see morning and bedtime steps in order and move the pieces as each job is done.', 'Rearrangeable pictures for the day, so your child can see what comes next and feel proud of each step. A supportive way to help you build steady morning and bedtime routines together.', 'Mainstream UK home timetable with rearrangeable cards matching whole-routine independence without school-only symbols.', NULL, 'buy', false, 'Parent-buy utility; not a gift unless parents asked.', 'Try phone photos of your real routine first - skip if that already works.', 'Small cards or tokens - supervise around younger siblings; store spares out of reach.', 'strong', ARRAY['https://www.amazon.co.uk/Create-Visual-Aids-communication-transition/dp/B093YJ5RL6', 'https://www.createvisualaids.co.uk/products/visual-timetable-for-home-1']::text[], 'none'),
    ('cat_visual_routine_cards', 2, 2, 'visible', true, true, 'Best for magnetic planners', 'Routine Planners for Kids', 'Little Goose', 'Haliburtons & Co.', 'https://haliburtons.com/products/routine-planners-for-kids', NULL, '£19.95', 'in_stock', 'Ages 2+ (Little Goose brand); stockist lists 3+', 'Magnetic routine planner strips for everyday jobs at home, so your child can see the order of the day and tick along as each small job is finished.', 'Magnetic planner strips for everyday jobs your child can see and tick along with. A supportive way to help you build steady morning and bedtime routines together.', 'Split AM/PM board with visible progress suits independence pride when whole-day charts feel like too much.', 'Only one on-page review; metal tokens need supervision around babies. Handmade lead time (Craftly ships Wed).', 'buy', false, 'Parent-buy utility; not a gift unless parents asked.', 'Try phone photos of your real routine first - skip if that already works.', 'Small cards or tokens - supervise around younger siblings; store spares out of reach.', 'strong', ARRAY['https://www.craftly.co.uk/products/childrens-daily-routine-board']::text[], 'none'),
    ('cat_visual_routine_cards', 3, 3, 'visible', true, true, 'Best for now and next', 'Mini Now and Next Board', 'Create Visual Aids', 'Create Visual Aids', 'https://www.createvisualaids.co.uk/products/mini-now-and-next-board', NULL, '£4.50', 'in_stock', 'Ages 2+ parent-setup preschool tool', 'A compact now and next board for simple hand-offs through the day, helping your child move from one job to the next with a clear picture plan.', 'A compact now and next board for simple hand-offs through the day. Helps your child practise moving from one job to the next with a clear picture plan.', 'Supports short transitions without a full-day board.', NULL, 'buy', false, 'Parent-buy utility; not a gift unless parents asked.', 'Try phone photos of your real routine first - skip if that already works.', 'Small cards or tokens - supervise around younger siblings; store spares out of reach.', 'specialist', ARRAY['https://www.craftly.co.uk/products/now-and-next-visual-routine-board']::text[], 'none'),
    ('cat_visual_routine_cards', 4, 4, 'visible', true, true, 'Best for portable routines', 'My Communication Book for Early Years Settings', 'Create Visual Aids', 'Amazon UK (sold by Create Visual Aids)', 'https://www.amazon.co.uk/Create-Visual-Aids-My-Communication-Book/dp/B0CJ5QXG8L', NULL, '£25.00 approx. (Amazon; confirm at checkout)', 'in_stock', 'Ages 2+ parent-setup preschool tool', 'A portable picture book for routines that travel between home, childminder and grandparents, so your child can see what comes next when the day changes place.', 'A portable picture book for routines that move between home, childminder and grandparents. Helps your child see what comes next when the day changes place.', 'Consolidates transition and routine symbols into one carryable book for families whose schedule moves between rooms or carers.', NULL, 'buy', false, 'Parent-buy utility; not a gift unless parents asked.', 'Try phone photos of your real routine first - skip if that already works.', 'Small cards or tokens - supervise around younger siblings; store spares out of reach.', 'strong', ARRAY['https://www.amazon.co.uk/Create-Visual-Aids-My-Communication-Book/dp/B0CJ5QXG8L']::text[], 'confirm_reviews_on_human_click'),
    ('cat_visual_routine_cards', 5, 5, 'visible', true, true, 'Best for leaving the house', 'Out The Door Chart', 'Create Visual Aids', 'Create Visual Aids', 'https://www.createvisualaids.co.uk/products/out-the-door-chart', NULL, '£12.00', 'in_stock', 'Ages 2+ parent-setup preschool tool', 'A picture strip for shoes, coat and bag before leaving the house, helping your child see the doorway steps and feel proud of each one.', 'An out-the-door picture strip for shoes, coat and bag. Helps your child see the leaving-home steps and feel proud of each one.', 'Supports the leave-the-house sequence with clear pictures.', NULL, 'buy', false, 'Parent-buy utility; not a gift unless parents asked.', 'Try phone photos of your real routine first - skip if that already works.', 'Small cards or tokens - supervise around younger siblings; store spares out of reach.', 'specialist', ARRAY['https://www.craftly.co.uk/products/visual-timetables-to-do-list']::text[], 'none')
  ) AS v(source_category_entity_id, pick_rank, longlist_rank, status, is_visible, is_locked, best_for_tag, product_name, brand, retailer, product_url, image_url, price_text, stock_status, age_mark_on_listing, product_description, ember_verdict, why_it_fits, caveats, buy_borrow_hold_off, gift_suitable, gift_note, ownership_note, safety_notes, evidence_tier, evidence_sources, founder_qa_flag)
)
INSERT INTO public.pl_stage3_picks (
  age_band_id,
  category_type_id,
  source_category_entity_id,
  pick_rank,
  longlist_rank,
  status,
  is_visible,
  is_locked,
  best_for_tag,
  product_name,
  brand,
  retailer,
  product_url,
  image_url,
  price_text,
  stock_status,
  age_mark_on_listing,
  product_description,
  ember_verdict,
  why_it_fits,
  caveats,
  buy_borrow_hold_off,
  gift_suitable,
  gift_note,
  ownership_note,
  safety_notes,
  evidence_tier,
  evidence_sources,
  founder_qa_flag,
  research_payload
)
SELECT
  '34-36m',
  ct.id,
  r.source_category_entity_id,
  r.pick_rank,
  r.longlist_rank,
  r.status,
  r.is_visible,
  r.is_locked,
  r.best_for_tag,
  r.product_name,
  r.brand,
  r.retailer,
  r.product_url,
  r.image_url,
  r.price_text,
  r.stock_status,
  r.age_mark_on_listing,
  r.product_description,
  r.ember_verdict,
  r.why_it_fits,
  r.caveats,
  r.buy_borrow_hold_off,
  r.gift_suitable,
  r.gift_note,
  r.ownership_note,
  r.safety_notes,
  r.evidence_tier,
  r.evidence_sources,
  r.founder_qa_flag,
  jsonb_build_object(
    'bundle_schema_version', 'stage3_ingestion_bundle_v1',
    'bundle_generated_at', '2026-07-23T05:53:34.920Z',
    'research_schema_version', 'ember_picks_research_v3',
    'source_category_entity_id', r.source_category_entity_id
  )
FROM stage3_rows r
JOIN public.pl_category_types ct
  ON ct.slug = r.source_category_entity_id
WHERE EXISTS (
  SELECT 1
  FROM public.pl_age_band_development_need_category_types abdnct
  WHERE abdnct.age_band_id = '34-36m'
    AND abdnct.category_type_id = ct.id
    AND abdnct.is_active = true
);

